# Version normalisée (sans accents, minuscules) pour matching souple
CITIES_NORMALIZED: frozenset[str] = frozenset(
    _normalize(n) for n in CITIES
)

import unicodedata as _ud


def _normalize(s: str) -> str:
    return _ud.normalize("NFD", s.lower()).encode("ascii", "ignore").decode()


def is_known_location(name: str) -> bool:
    """Retourne True si name est une ville ou un pays connu."""
    if name in CITIES:
        return True
    return _normalize(name) in CITIES_NORMALIZED
